def isPalindrome(s):
    # Messy: Creates a new string, uses regex or complex filtering
    new_s = ""
    for char in s:
        if char.isalnum():
            new_s += char.lower()

    # Inefficient: Creates another copy of the string just to reverse it
    return new_s == new_s[::-1]

